INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'null', 'F型アップコン (丸形)', '便利さと美しさが選べる。手軽に使えるアップコン。器具寸法: φ110×65 (コンセント収納時)。プレート寸法: 器具プレート一体型。施工床条件: 床材厚み 12~45、必要床仕上げ高さ 61以上。床面穴加工寸法: φ83~87。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=null', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 110, 65, NULL);
