INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'null', 'フロアコンラウンド', 'コンパクトで上質感のあるデザイン。器具寸法: φ110×92。プレート寸法: φ78。施工床条件: 必要床仕上げ高さ 床材厚み12以上60以下の場合100以上、床材厚み60超120以下の場合140以上。床材厚み12~120。床面穴加工寸法: φ85~92。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=null', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 110, 92, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'null', 'フロアコンスクエア', 'コンパクトで上質感のあるデザイン。器具寸法: 142×133。プレート寸法: 111。施工床条件: 必要床仕上げ高さ 床材厚み12以上60以下の場合140以上、床材厚み60超120以下の場合150以上。床材厚み12~120。床面穴加工寸法: □125~128角部φ40(直角)~φ16。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=null', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 142, 133, NULL);
