INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WTK24878W', '天井取付 熱線センサ付自動スイッチ (屋内軒下共用) (親器・8A・広角検知形) (検知後連続動作時間約10秒~30分可変形) (明るさセンサ付) (ホワイト)', '8A 100~242V AC. 最大8Aまでの負荷をセンサで制御させたい場合におすすめ。ボルトフリー対応、高容量対応、多箇所検知形(子器を12台まで接続可能)、広角検知形、換気扇連動用子器(WTK29328W, WTK29428Wなど)との組み合わせにより、照明と換気扇の連動制御可能、気密対応、ブローイング対応(3Aまで)(100Vのみの仕様です)。', 19500, 'https://dummyimage.com/200x200/cccccc/000.png&text=WTK24878W', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 75, 66.7, 59.2);
