INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3124', '高天井用 熱線センサ付自動スイッチ (スマート設定器式) (親器) (明るさセンサ付) (天井取付形)', 'AC100~242V。白熱灯照明器具から40cm以上離してください。親器のみでご使用できます。天井の高い空間用の熱線センサ付自動スイッチ。センサ制御可能な場所が増え省エネを実現します。スマート設定器(WRT9510K)とスマートフォン(アプリ・フル2線 センサ設定)での設定変更は床面から可能です。壁スイッチでセンサ入切可能。', 50000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3124', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3125', '高天井用 熱線センサ付自動スイッチ (子器) (天井取付形)', '白熱灯照明器具から40cm以上離してください。子器のみの使用はできません。天井の高い空間用の熱線センサ付自動スイッチ。センサ制御可能な場所が増え省エネを実現します。スマート設定器(WRT9510K)とスマートフォン(アプリ・フル2線 センサ設定)での設定変更は床面から可能です。壁スイッチでセンサ入切可能。', 36000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3125', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
