INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT36179', '調光T/U付照度センサ (スマート設定器式) (天井埋込形)', 'AC100~242V。外光に合わせて平均照度を一定に保って調光。快適性も保ちながら、上手に節電。ランプ交換当初の余分な明るさをカットして節電。当社製調光型LED照明器具対応。タイマーとの連動でさらに節電。壁スイッチからの調光も可能。', 39500, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT36179', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3618', '調光T/U付照度センサ (スマート設定器式) (天井露出形)', 'AC100~242V。外光に合わせて平均照度を一定に保って調光。快適性も保ちながら、上手に節電。ランプ交換当初の余分な明るさをカットして節電。当社製調光型LED照明器具対応。タイマーとの連動でさらに節電。壁スイッチからの調光も可能。', 51500, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3618', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT9510K', 'スマート設定器', 'フル2線式リモコン。スマートフォンを使って設定が可能。', 84000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT9510K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3655K', '照度センサスイッチ (照度・アドレス設定部壁埋込形) (センサ部軒下天井取付形)', 'プレート別売。外光の明るさを検知して照明を制御します。明るい間の不要な点灯を省きます。(照度設定の目安:60 lx~9080 lx)。照度設定は管理室の壁に設置した照度・アドレス設定部から行えます。個別・パターン・グループ制御可能です。駅ホームの軒下天井や、工場・倉庫などの高天井におすすめします。', 42000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3655K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3657', '照度センサスイッチ(光アドレス設定式) (動作照度調整機能付) (天井取付形)', '屋外からの自然光の明るさを検知して照明を制御します。(検知照度の目安:100 lx~2000 lx)。照度センサを不動作にして強制的にON/OFFが可能です。2つの範囲の負荷を異なる照度で制御できます。個別・パターン・グループ制御可能です。机上面照度を基準に制御可能です。(天井と机上の照度の相関比率を記憶)。ハイコストパフォーマンスで、さらに接点入力T/Uも不要です。', 29700, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3657', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT1700K', 'フル2線式リモコン 調光調色T/U付明るさセンサ (電波式) (埋込)', '無線調光通信方式「WiLIA」専用照明器具を、調光信号線なしで調光制御が可能。調光信号線が不要のため、配線工事なしでレイアウト変更が可能。外光に合わせた目標照度への自動制御による省エネ。年間プログラムタイマを併用し、スケジュール連動が可能。調色制御にも対応が可能に。', 48500, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT1700K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT1701K', 'フル2線式リモコン 調光調色T/U付明るさセンサ (電波式) (露出)', '無線調光通信方式「WiLIA」専用照明器具を、調光信号線なしで調光制御が可能。調光信号線が不要のため、配線工事なしでレイアウト変更が可能。外光に合わせた目標照度への自動制御による省エネ。年間プログラムタイマを併用し、スケジュール連動が可能。調色制御にも対応が可能に。', 61000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT1701K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3540K', '年間プログラムタイマユニット (ソーラー機能付) (フル2線信号出力形) (分電盤用)', 'スケジュールに対応したタイマーによる照明制御が可能。タイマーによる照明制御を最大30通り行うことができます。(分単位)。年間スケジュール対応可能。毎年のくりかえし(○月○日や○月の第○週の○曜日)や1回限りで13ヵ月先までの年月日の設定ができます。日の出、日の入りに対応したソーラータイマ機能付。(全国12地区)。本器同士、または仕様を満たした親時計と同期をとることが可能。定時消灯後の手動点灯に対する再消灯に便利な繰り返しのパターン動作が可能。フル2線スイッチから休日(特日) 動作への切替・解除、タイマー有効/無効が可能。フル2線信号直結形。接点入力T/Uとタイマーの機能を一つにまとめ、またタイマーの小形化によりリレー制御盤の省スペース化が図れます。', 86000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3540K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3251K', 'EEスイッチ連動ユニット (1入力用) (光アドレス設定式) (分電盤用)', 'EEスイッチ(明暗による自動点滅)との接続で、個別・グループ・パターン制御が可能です。動作の有効/無効が切り替えられ、休日の動作停止に便利。', 17000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3251K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3224K', '接点入力T/U(4入力用) (光アドレス設定式) (分電盤用)', '接点入力T/Uに他システムからの信号(無電圧接点)を接続することにより、個別・グループ・パターン制御が可能です。', 18100, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3224K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT3211', '接点入力T/U(1入力用) (光アドレス設定式) (分電盤用)', '接点入力T/Uに他システムからの信号(無電圧接点)を接続することにより、個別・グループ・パターン制御が可能です。', 12500, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT3211', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WRT9600K', '小形パターン・グループ設定器 (アドレス設定機能付)', 'ワイヤレスアドレス設定機能あり。小形パターン・グループ設定器1台で〈アドレス設定〉と〈パターン・グループ制御内容設定〉が可能です。パターン・グループの設定・変更を机上で行い、後からフル2線信号線に接続することにより、設定・変更内容を伝送ユニットに記憶可能です。また、伝送ユニットに記憶されている制御内容を小形パターン・グループ設定器に入力し保管することができます。パターン制御の内容設定時、個別アドレス使用の調光レベル設定ができます。パターン制御の内容設定時、フェード時間の設定が可能です。個別・グループ・パターン・調光制御の動作確認およびシステム状態確認が可能です。', 84500, 'https://dummyimage.com/200x200/cccccc/000.png&text=WRT9600K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
