INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'null', 'ホームナビゲーション モニター', '専用充電台より供給/DC7.4V (充電式電池端子)。動作時(充電完了時):約9.5W、動作時(充電中):約13W。リチウムイオン充電式電池(内蔵) 電圧:7.4V 容量:3100mAh(最小)。10V型液晶ディスプレイ(横1024×縦600)。スピーカー出力:800mW+800mW。ヘッドホン出力:ステレオミニジャック(φ3.5mm、16~320Ω推奨)。マイク:モノラル。充電式電池持続時間:約2時間10分(スピーカー使用/画質「スタンダード」)、約2時間30分(ヘッドホン使用/画質「ユーザー」/明るさ「-5」)、約2時間20分(ヘッドホン使用/画質「スタンダード」)、約2時間10分(ヘッドホン使用/画質「ダイナミック」)。保護等級:IPX6/IPX7相当。内蔵無線LANモジュール規格:IEEE802.11ac/n/a/g/b準拠(5GHz帯は屋内使用限定)。内蔵無線LANモジュールセキュリティ:TKIP/AES、PSK WEP(64bit/128bit)。内蔵デジタルコードレスモジュール通信方式:1.9GHz TDMA-WB、規格:ARIB STD-T101。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=null', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 255, 180, 39);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'null', 'ホームナビゲーション ホームサーバー', 'AC100V、50/60Hz。消費電力:約13W、待機時:約4W。質量:約0.6kg。許容周囲温度:5℃~40℃。許容相対湿度:10%~80%RH(結露なきこと)。HDD容量:500GB(システム領域を含む)。地上デジタル入力:90MHz~770MHz 75Ω。BS・110度CSデジタル-IF入力:1032MHz~2071MHz 75Ω。チューナー数:2(地上デジタル/BS・110度CSデジタル視聴用:1、録画用:1)。記録圧縮方式:MPEG-2(DRモード)、MPEG-4 AVC/H.264(1.5倍録~15倍録モード)。記録圧縮音声:MPEG-2 AAC(最大5.1ch記録)。内蔵無線LANモジュール規格:IEEE802.11ac/n/a/g/b準拠(5GHz帯は屋内使用限定)。内蔵無線LANモジュールセキュリティ:TKIP/AES、PSK WEP(64bit/128bit)。USB端子:後面1系統(USBメモリ用)。LAN端子:1系統 10BASE-T/100BASE-TX。HDMI端子:1系統。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=null', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 204, 43, 145);
